# Bootstrap: imports unmanaged SygnumPCFComponents 8.0.10 (NpOnboardingChecklist only)
# Step 1 of 2: Run this FIRST to register the control in D365, then import the managed upgrade.
$b64 = ""
$bytes = [Convert]::FromBase64String($b64)
$outPath = "$env:USERPROFILE\Desktop\SygnumPCFComponents_8.0.10_unmanaged.zip"
[System.IO.File]::WriteAllBytes($outPath, $bytes)
Write-Host "Saved to: $outPath"
Write-Host "Import this as UNMANAGED solution in make.powerapps.com, then import the managed upgrade."